ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  id: vars.taskId,
  contextId: vars.contextId,
  kind: "task",
  status: {
    state: "completed",
    message: {
      role: "agent",
      kind: "message",
      messageId: (now() as String) ++ "-" ++ vars.taskId,
      parts: [
        { kind: "text", text: vars.replyText default "" }
      ]
    },
    timestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss'Z'" }
  }
}

%dw 2.0
output application/java
---
[
  { "type": "function", "function": {
      name: "resolve_supplier",
      description: "サプライヤー名/ヒントから ゴールデン ID を解決。matched=false でも success で返る",
      parameters: {
        "type": "object",
        properties: {
          supplierName: { "type": "string" },
          hint:         { "type": "string" }
        },
        required: ["supplierName"]
      }
  }},
  { "type": "function", "function": {
      name: "list_suppliers",
      description: "条件指定 (region / status / リスクスコア範囲 / limit) で ACTIVE な取引先一覧を返す",
      parameters: {
        "type": "object",
        properties: {
          region:       { "type": "string" },
          status:       { "type": "string" },
          riskScoreMin: { "type": "number" },
          riskScoreMax: { "type": "number" },
          limit:        { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "list_regions",
      description: "Region__c のユニーク値と各 region の ACTIVE 取引先件数を返す",
      parameters: { "type": "object", properties: {}, required: [] }
  }},
  { "type": "function", "function": {
      name: "resolve_part",
      description: "部品番号 (Part__c.Name) から部品詳細を 1 件解決 (READ-ONLY)。在庫/LT/主供給元/代替候補数",
      parameters: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" }
        },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "list_parts",
      description: "条件指定 (supplierGoldenId / category / location / nameLike / limit) で部品一覧",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          category:         { "type": "string" },
          location:         { "type": "string" },
          nameLike:         { "type": "string" },
          limit:            { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "list_part_alternatives",
      description: "部品の代替品一覧 (CompatibilityScore DESC)",
      parameters: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" },
          limit:      { "type": "integer" }
        },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "find_suppliers_for_part",
      description: "部品を供給可能なサプライヤー一覧 (主+代替経由、 RiskScore ASC)",
      parameters: {
        "type": "object",
        properties: {
          partNumber: { "type": "string" },
          limit:      { "type": "integer" }
        },
        required: ["partNumber"]
      }
  }},
  { "type": "function", "function": {
      name: "get_supplier_relations",
      description: "ゴールデン ID から親会社・子会社・過去インシデント・代替部品候補を取得",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          depth:            { "type": "integer" }
        },
        required: ["supplierGoldenId"]
      }
  }},
  { "type": "function", "function": {
      name: "list_incidents",
      description: "インシデント一覧 (CreatedDate DESC、 既定 limit=10、 上限 50)",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          partNumber:       { "type": "string" },
          status:           { "type": "string" },
          severity:         { "type": "string" },
          since:            { "type": "string" },
          limit:            { "type": "integer" }
        },
        required: []
      }
  }},
  { "type": "function", "function": {
      name: "update_supplier_risk_score",
      description: "サプライヤーのリスクスコア (0..1) を更新。previousRiskScore を返す",
      parameters: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          riskScore:        { "type": "number" },
          reason:           { "type": "string" },
          incidentId:       { "type": "string" }
        },
        required: ["supplierGoldenId", "riskScore"]
      }
  }},
  { "type": "function", "function": {
      name: "update_ontology",
      description: "KG に subject/predicate/object のトリプルを記録。tripleId を返す",
      parameters: {
        "type": "object",
        properties: {
          subject:    { "type": "string" },
          predicate:  { "type": "string" },
          "object":   { "type": "string" },
          incidentId: { "type": "string" }
        },
        required: ["subject", "predicate", "object"]
      }
  }}
]

%dw 2.0
output application/java
fun safeReadJson(s: String) =
  if (s == null or trim(s) == "") {}
  else read(s, "application/json")
---
if (payload == null) {}
else if (payload is Binary) safeReadJson(payload as String { encoding: "UTF-8" })
else if (payload is String) safeReadJson(payload as String)
else payload
